1000	
1001	  // Exposed for testing — not part of the public API
1002	  window._chatInternals = {
1003	    handleServerMessage: handleServerMessage,
1004	    handleUpdate: handleUpdate,
1005	    appendAgentText: appendAgentText,
1006	    appendUserBubble: appendUserBubble,
